var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"진짜로 괜찮겠어?","JPN":"本当にいいの？","ENG":"Are you sure about this?","TWN":"真的沒關係嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"음식 같은 거 먹으면 안 되는데, 내가 연습했다고 해서 괜히 무리하는 건 아니지?","JPN":"本当は食べちゃダメなのに、私が練習したからって無理してない？","ENG":"You're not supposed to eat food. You're not just forcing yourself because I practiced, are you?","TWN":"你不能吃東西的吧？是不是因為我說練習了，你才吃的啊？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"괜찮아. 영양섭취가 불필요하다 하여 그것을 즐기지 못하는 건 아니니까.","JPN":"いいのだ。栄養の摂取が不要とはいえ、食を楽しめないわけではないからな。","ENG":"It's fine. I may not need food to survive, but that doesn't mean I can't enjoy it.","TWN":"沒關係。即使不需要攝取營養，也不代表不能享受美食。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맛도 다 느낄 수 있는 거야?","JPN":"味もちゃんと分かるの？","ENG":"And you can still taste everything?","TWN":"可以嚐出來味道嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"맛을 느끼는 건 인공감각수용체지만, 맛있는 걸 먹었을 때 기쁜 것은 틀림없는 본인일세.","JPN":"味を感じるのは人工感覚受容体だが、美味いものを食べて嬉しいと思うのは、間違いなく某自身だ。","ENG":"The taste comes from artificial receptors, but the joy of good food is still mine.","TWN":"雖然感受到味道的是人工感官受體，但我吃到美味的東西還是會感到開心。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…어때? 맛있어?","JPN":"……どう？　美味しい？","ENG":"...So? How is it? Good?","TWN":"……怎麼樣？好吃嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"걱정 말게. 내 쪽에서 염분수용감각의 예민도를 35% 정도 낮추면 될 일이야.","JPN":"心配はいらん。某が塩分受容感覚の敏感度を35％程下げればいいことだ。","ENG":"Don't worry. I can just dial down my salt sensitivity by about thirty-five percent.","TWN":"別擔心。我只需將鹽分感知的敏感度降低35%就行了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"좀 짜다는 거지? 거 되게 솔직하시네요.","JPN":"それ、塩っぱいってことだよね？　正直な感想ありがと。","ENG":"So it is salty? Wow, you really don't hold back.","TWN":"有點鹹是吧？你還真是坦率呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…만일 내가 살아있었다면, 이 짠 맛에 사무쳐 울음을 터뜨렸을 지도 모르겠군.","JPN":"……もし某が生きていたら、この塩っぱさが身に染みて涙を流していたかもしれんな。","ENG":"...If I were still alive, this saltiness alone might have brought me to tears.","TWN":"…如果我還活著，可能會因為這鹹味忍不住哭出來吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그, 그 정도야?","JPN":"そ、そんなに？","ENG":"I-it's that much?","TWN":"有……有那麼誇張嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"다시… 만들까?","JPN":"作り……直そうか？","ENG":"Should I... make new ones?","TWN":"要不我還是重新做一份吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"맛없다는 게 아닐세. 그만큼이나 그리웠던 것 같아.","JPN":"不味いという意味ではない。どうやら某はそれほど懐かしかったようだ。","ENG":"I never said it was bad. I think it's simply that I've missed this...","TWN":"不是說不好吃，我只是很懷念。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"식탁에 이리 둘러앉아 두런두런 나누는 이 따스한 온기를.","JPN":"こうして食卓を囲み、話し合う時間の温かいぬくもりが。","ENG":"This warmth of sitting around a table, talking together like this.","TWN":"懷念我們圍在餐桌旁的溫暖。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시윤 군은 어떤가? 앤디의 진수성찬.","JPN":"シリュウ君はどうだ？　アンディーの料理。","ENG":"And you, Shiyoon? What do you think about Andy's grand feast?","TWN":"時雲覺得安狄準備的豐盛的飯菜怎麼樣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아하하, 두 분을 방해하고 싶지 않아서 조용히 먹고만 있었는데 말이죠.","JPN":"ハハ、お二人を邪魔したくないと思って、黙って食べていましたが。","ENG":"Ahaha, I kept quiet because I didn't want to interrupt the two of you.","TWN":"啊哈哈，我本打算安靜地吃，不想打擾你們兩位。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"표현하자면 그리운 집밥의 맛이랄까요? 정성이 느껴져서 좋네요.","JPN":"あえて表現するなら、懐かしい家庭料理の味って感じですね。真心が伝わってきます。","ENG":"But if I had to describe it... I'd say it tastes like home cooking. Nostalgic, heartfelt.","TWN":"如果要形容的話，就像是久違的家常菜的味道吧？能感受到她的用心，很好吃。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그냥 맛있다 한 마디면 될 텐데. 두 사람 다 쉬운 길로 갈 생각이 없구나?","JPN":"一言、美味しいでいいのに。二人とも小難しい言い回しが好きなんだね？","ENG":"You could've just said it was good. Do neither of you know how to take the easy route?","TWN":"就說好吃不行嘛？你們兩個真的是。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시윤 군의 반응은 제법 호평이라 생각했는데 말이지.","JPN":"シリュウ君の感想はかなり好評に近いと思ったのだが。","ENG":"I thought Shiyoon's reaction sounded quite favorable.","TWN":"我以為時雲是在誇獎呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 서생 씨의 혹평 때문에 이미 상처받으신 게 아닐까요?","JPN":"ショウさんの酷評で、既に傷ついていたんじゃないでしょうか？","ENG":"Maybe it's because your harsh critique already hurt her feelings.","TWN":"恐怕是因為書生的苛刻評價，讓她受傷了吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"크흠, 미안하군.","JPN":"ゴホン……すまない。","ENG":"Ahem. My apologies.","TWN":"咳咳，抱歉了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"됐어. 결국 제일 좋아하는 음식을 맛있게 못 만들어준 내가 원인이지 뭐.","JPN":"いいよ。一番の好物を美味しく作ってあげられなかった私が悪いんだから。","ENG":"Forget it. The real problem's me not being able to cook his favorite dish the way it should be.","TWN":"算了算了，最終還是因為我沒能做好是吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 갈비찜 다 됐나보다. 금방 다녀올게.","JPN":"あ、肉じゃがが出来上がったみたい。ちょっと待ってて。","ENG":"Ah, sounds like the galbi-jjim's done. Be right back.","TWN":"啊，燉排骨應該好了，我去拿過來。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 신기하네요. 저희 아버지도 계란찜을 제일 좋아하셨거든요.","JPN":"それにしても、奇遇ですね。僕のお父さんも茶碗蒸しが一番の好物だったんです。","ENG":"Funny, my father's favorite was steamed egg too.","TWN":"不過真神奇啊，我父親也最喜歡吃蒸蛋呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"세상이 변해도, 기호라는 건 쉽게 바뀌지 않나 봐요.","JPN":"世の中が変わっても、人の嗜好はそう簡単に変わらないものなんですかね。","ENG":"I guess some preferences never change, no matter how the world does.","TWN":"即使世界改變，喜好似乎也不容易改變呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기호라…","JPN":"嗜好か……","ENG":"Preferences, you say...","TWN":"喜好啊…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시윤 군은 혹시 곶감을 좋아하는가?","JPN":"シリュウ君は、干し柿は好きだろうか。","ENG":"Do you like dried persimmons, Shiyoon?","TWN":"時雲喜歡柿餅嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어머니께서 많이 좋아하셨죠.","JPN":"お母さんが大好きでしたね。","ENG":"My mother loved them.","TWN":"母親非常喜歡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 아버지를 닮은 편이라 계란찜을 더 좋아했지만요.","JPN":"僕は父親似で、茶碗蒸しのほうが好きでしたが。","ENG":"I take after my father more, so I've always preferred steamed egg.","TWN":"我比較像我父親，所以更喜歡蒸蛋。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리자 나리가 나라는 사람에 대해 설명해주었나?","JPN":"管理者殿から、某について説明は聞いているのか？","ENG":"Did the Administrator tell you about me?","TWN":"管理者有跟你提到過我這個人嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 들었습니다. 범에 대해서도…","JPN":"もちろん聞いています。虎についても……","ENG":"Of course. About the Tiger too...","TWN":"當然聽說過。還有那個虎…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…그런 터무니없는 존재를 막기 위한 과정에 어떤 희생이 필요했는지도요.","JPN":"……そんなとんでもない存在を止めるために、どんな犠牲を払ったのかについても。","ENG":"...And the sacrifices it took to fight something that absurd.","TWN":"…你為了阻止那荒謬的存在，付出了很大的犧牲。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"미안하네.","JPN":"すまない。","ENG":"I'm sorry.","TWN":"……對不起。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"최선을 다한 결말이 고작 이런 것이라서.","JPN":"最善を尽くした結果が、こんなもので。","ENG":"That all my efforts amounted to nothing more than this.","TWN":"儘管我拼盡全力，結局也只是這樣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…서생 씨.","JPN":"……ショウさん。","ENG":"...Seosaeng.","TWN":"……書生。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그리고 고맙네.","JPN":"そして、感謝する。","ENG":"And thank you.","TWN":"還有，謝謝。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"끝끝내 무너지지 않고 잘 견뎌주어서.","JPN":"最後まで挫けず、耐えてくれて。","ENG":"For enduring without breaking, all the way to the end.","TWN":"你沒有崩潰，堅強地撐住了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"얼마 전까진 상상조차 못했어요.","JPN":"少し前までは、想像もできませんでした。","ENG":"Not long ago, I never could've imagined it.","TWN":"不久前我甚至無法想像。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가족에 관한 이야기를, 다시 이런 기꺼운 마음으로 나눌 사람이 생길 줄은.","JPN":"また気兼ねなく家族の話ができる人に出会えるとは。","ENG":"That I'd have someone I could talk to about family with joy in my heart again.","TWN":"沒想到我還能有機會與人分享我的喜悅。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"...Yes.","TWN":"…是啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"세상 일… 참 알다가도 모를 일이야.","JPN":"世には……不思議なことが多いものだ。","ENG":"The world... always has a way of surprising us.","TWN":"……世事難料啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저희 아버진 짐승의 피가 한 방울도 섞이지 않은 분이셨습니다.","JPN":"お父さんはケモノの血が一滴も流れていない人でした。","ENG":"My father didn't have a single drop of Beast Blood.","TWN":"我父親身上沒有流淌獸血。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리자님이 서생 씨를 택한 건, 아마도 그런 이유일 거라 생각해요.","JPN":"最高管理者がショウさんを選んだのは、おそらくそのせいでしょう。","ENG":"I think that's why the Administrator chose you, Seosaeng.","TWN":"我想，可能管理者也是基於這個原因選擇書生的吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そうだな。","ENG":"...Yeah.","TWN":"…是啊。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"앞으로 벌어질 인과에 대응하려면 그 힘이 필요한 것이겠지.","JPN":"これから訪れる因果に対応するためには、その力が必要なのだろう。","ENG":"To face the causality before us, that power will be needed.","TWN":"但想要應對之後的因果，還是需要那股力量。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"하지만 아직 의문이 남는군.","JPN":"だが、まだ疑問が残る。","ENG":"But I still have questions.","TWN":"但我仍然有疑問。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"의식이 온전하다 한들, 이 몸에는 아무것도 흐르지 않아.","JPN":"意識がはっきりしているとはいえ、この身体には何も流れておらん。","ENG":"Even if my consciousness is intact, there's nothing flowing through this body anymore.","TWN":"即便意識清醒，這具身體中也沒有任何流動的東西。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리자 나리는 어째서 짐승의 피도 없는 본인을…","JPN":"管理者殿はなぜ、ケモノの血を持たぬ某を……","ENG":"Why would the Administrator choose someone like me, with no Beast Blood–","TWN":"管理者為何會選擇沒有獸血的我…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"꺄아아!","JPN":"きゃああ！","ENG":"Kyaah!","TWN":"呀啊啊！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"베스카 씨…?","JPN":"ベスカーさん……？","ENG":"Ms. Vesca...?","TWN":"貝斯卡……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"앤디! 무슨 일인가!","JPN":"アンディー！　何事だ？","ENG":"Andy! What's wrong?!","TWN":"安狄！出什麼事了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기… 호랑이…","JPN":"あの……虎が……","ENG":"There's... a tiger...","TWN":"那個……老虎……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호랑이요?","JPN":"虎？","ENG":"A tiger?","TWN":"老虎嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 호랑이가 내 갈비찜을 다 먹어 치웠어!","JPN":"あの虎が、私の肉じゃがを全部食べちゃったの！","ENG":"That tiger ate all my galbi-jjim!","TWN":"那隻虎把我的燉排骨全吃光了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"아야야야…","JPN":"いたたた……","ENG":"Oww...","TWN":"啊呀呀呀……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"고기 냄새가 나길래 손 좀 댔기로 서니, 다짜고짜 프라이팬으로 머릴 내려치는 경우가 어딨냐?!","JPN":"肉の匂いがするからちょっといただいただけなのに、いきなりフライパンで殴るなんてひどいじゃん！","ENG":"I smelled meat and went to take a little, and you hit me on the head with a frying pan without warning?!","TWN":"我聞到了肉香就想嚐一嚐，哪有用平底鍋砸人家頭的道理啊？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗, 사람 말도 하잖아?","JPN":"あっ、喋ってる！","ENG":"Huh, it talks?","TWN":"啊，還會說人話？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"왜 그 부분에서 놀라? 실수로 사람을 쳤으면 사과부터 할 것이지.","JPN":"ツッコむとこそこかよ！　間違って人を殴ってしまったなら、謝るのが先でしょ。","ENG":"Why is that the part that surprises you? If you hit a person by mistake, you should apologize first.","TWN":"重點不是那個吧？不小心打了人不是得先道歉嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"실수 아니거든요? 그쪽이 무단침입에 무단취식도 모자라서…","JPN":"間違ってないよ？　だってそっちが勝手に入ってきて勝手に食べて、それに……","ENG":"It wasn't a mistake. On top of trespassing, you ate without permission...","TWN":"我可不是不小心的，是你不僅擅自闖入，還擅自吃東西……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…사람한테 붙어있으면 안 되는 것까지 달고 다니니까 이러는 거잖아요!","JPN":"……人間にはないはずのモノつけてるからじゃない！","ENG":"...And you're walking around with things that shouldn't be attached to a person!","TWN":"那還不是因為你有人類沒有的尾巴！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"오냐, 사람 아니다. 어쩔래? 짐승처럼 확 물어줄까?","JPN":"そう、私は人間じゃない。で？　獣みたいに噛みついてほしい？","ENG":"You're right. I'm not a person. So what? Should I bite you like a beast?","TWN":"喔，你說我不是人，那又怎樣？要不要像野獸一樣咬你一口？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"앤디. 조심하게.","JPN":"アンディー、気をつけたまえ。","ENG":"Andy. Be careful.","TWN":"安狄，小心。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기운은 느낄 수 없으나, 풍채가 범인은 아니로군.","JPN":"気配は感じられんが、見た目からしてただ者ではないようだ。","ENG":"I can't sense her energy, but her appearance tells me she's no ordinary person.","TWN":"雖然感受不到氣息，但氣度非凡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"흥, 나 같은 건 처음 본다 이거냐?","JPN":"ふん、私なんか知らないってことか。","ENG":"Hmph, first time seeing one like me?","TWN":"哼，像我這樣的你是第一次見到嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"서생, 네놈만 아니었어도 내가 이 고생을 하고 있진 않았을 텐데.","JPN":"ショウ、私がこんな苦労をする羽目になったのは、全部あなたのせいなんだから。","ENG":"Seosaeng, if it weren't for you, I wouldn't be in this mess in the first place.","TWN":"書生，要不是因為你，我就不會受這份苦了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"나를 알고 있나?","JPN":"某を知っているのか？","ENG":"You know who I am?","TWN":"你認識我嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"알다마다. 네놈도 나를 알아야 할 거다.","JPN":"知ってるも何も。あなたも私のことは覚えてたほうがいいよ。","ENG":"Of course. And you should know me.","TWN":"當然，你也應該認識我才對。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내가 태어난 건, 전부 네놈 탓이니까.","JPN":"なにせ私が生まれたのは、全部あなたのせいなんだから。","ENG":"You're the reason I exist at all.","TWN":"我之所以會誕生，全都是因為你這傢伙。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"잠깐만. 이건 무슨 참신한 족보야?","JPN":"待って、家系図どうなってるの？","ENG":"Hold on. What kind of messed-up family tree is this?","TWN":"等一下。這是什麼新奇的家譜？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러니까 패러독스… 당신이 사부 때문에 태어난 거라고?","JPN":"つまり、パラドックス……あんたが生まれたのは師匠のせいなのね？","ENG":"So Paradox... you're saying you were born because of Master?","TWN":"所以悖論……你是因為師父而誕生的嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"말 그대로다. 저 녀석이 아니었으면 난 존재하지도 않을 운명이었어.","JPN":"そう。あいつがいなければ私は存在すらしない運命だった。","ENG":"Exactly. If not for him, I was fated not to exist.","TWN":"字面意思，如果不是那傢伙，我根本就不會存在。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그러니 따지고 보면 저 녀석이 내 아빠인 셈인 게다.","JPN":"だから、あいつは私の父親も同然だね。","ENG":"So if you put it that way, that makes him my dad.","TWN":"所以說起來，那傢伙算是我爸爸。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아… 빠…?","JPN":"父……親……？","ENG":"D-dad...?","TWN":"爸……爸……？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그치만 내가 아는 기억대로라면… 그건 불가능…","JPN":"でも、私が覚えている限りじゃ……そんなの不可能……","ENG":"But as far as I remember... that's impossible...","TWN":"但是如果按照我的記憶……那是不可能的……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아니지. 사부가 관리국에 들어가기 전이라면 가능한가…? 대체 언제…?!","JPN":"いや、師匠が管理局に入る前ならできなくもない……？　いったいいつ……！？","ENG":"No, wait. If it was before Master joined the Administration, maybe...? But when exactly...?!","TWN":"不對。如果是在師父進入管理局之前的話，還是有可能的吧…？到底是什麼時候…？!"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서생 씨, 혹시 생전에 연화라는 이름 말고도 만나는 여성분이 계셨나요?","JPN":"ショウさん、生前にレンカという名前の女性以外にお付き合いした女性はいましたか？","ENG":"Seosaeng, while you were alive, did you meet any women other than one named Yeonhwa?","TWN":"書生，你在世時，除了叫蓮華的女性之外還交往了其他女性嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가령 저런 꼬리가 달려있었다던가.","JPN":"例えば、あのような尻尾がついていた女性とか。","ENG":"One with a tail like that, for example?","TWN":"比如說，有那種尾巴的人。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"미안하군. 그런 기억은 떠오르지 않는데.","JPN":"すまない。そういう記憶は思い出せんのだが。","ENG":"I'm sorry. No such memory comes to mind.","TWN":"抱歉，我沒有那種記憶。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이것도 정보오염의 일종인가?","JPN":"これも情報汚染の一種か？","ENG":"Is this also a kind of data corruption?","TWN":"這也是資訊污染的一種嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…푸하핫-","JPN":"……ぷはっ！","ENG":"...Pff– Haha.","TWN":"……噗哈哈。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"미안, 미안. 재밌는 소재거리가 나올 거 같아서. 장난 좀 쳐봤다.","JPN":"ごめん、ごめん。面白いネタになりそうだなと思って、ちょっといたずらしてみただけだよ。","ENG":"Sorry, sorry. Thought I'd get some fun material. I was just teasing you.","TWN":"抱歉，抱歉。我覺得會有有趣的話題出現，所以開了個小玩笑。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그치? 전부 다 농담… 이었던 거지?","JPN":"そうだよね？　全部冗談……だよね？","ENG":"Right? It was all a joke... right?","TWN":"對吧？這一切都是玩笑……對吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 절반 정도는?","JPN":"まあ、半分ぐらいは？","ENG":"Well... maybe half of it?","TWN":"嗯，大概一半吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"야, 꼬맹이! 조리있게 말 안 할래?! 관리국 출신이라면서 왜 그렇게 설명을 못하는 거야!","JPN":"ちょっと！　はっきり言いなさいよ！　管理局出身のくせに、説明もろくにできないの！？","ENG":"Hey, kid! Can you speak clearly?! You said you're from the Administration! So why can't you explain anything?!","TWN":"喂，小鬼！能不能說得清楚一點？！管理局出身的人表達能力怎麼這麼糟糕！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래? 내가 설명을 좀 빼먹었던가?","JPN":"そう？　ちょっとはしょりすぎたかな？","ENG":"Oh yeah? Did I leave out some explanations?","TWN":"是嗎？難道是我漏掉了一些重點？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"누가 사정없이 후려치는 바람에 머릿속이 뒤죽박죽 엉망진창이 되어버려서 말이지.","JPN":"誰かさんに容赦なく叩かれたせいで、頭の中がこんがらがってしまってさ。","ENG":"Someone smacked me around without mercy, so now my head's a complete mess.","TWN":"被人狠狠地打了一下，腦子都轉不過去了。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"윽…","JPN":"ぐっ……","ENG":"Ngh...","TWN":"呃…"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그… 내 반응이 좀 과했던 건 사과할게.","JPN":"その……私が過剰に反応しちゃったことは謝るよ。","ENG":"Um... I'm sorry for overreacting.","TWN":"那個…我為我的應激反應道歉。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그치만 나도 그 갈비찜 만들려고 하루 온종일 고생했다고.","JPN":"でも私だって、丸一日かけてあの肉じゃが作ったんだから。","ENG":"But I worked all day to make that galbi-jjim.","TWN":"可是我為了做那道燉排骨也辛苦了一整天呢。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래?","JPN":"ふうん？","ENG":"Yeah?","TWN":"是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 맛있긴 했으니까. 이쯤에서 용서해줄까?","JPN":"ま、美味しかったし許してあげるか。","ENG":"Well, it was tasty. I suppose I can forgive you now.","TWN":"嗯，味道還不錯。就到此為止，原諒我吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…흥.","JPN":"……ふん。","ENG":"...Hmph.","TWN":"…哼。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그래서… 그대가 말한 것 중 절반의 진실이라는 건 무엇이지?","JPN":"それで……そなたの話で、半分の真実とは何だ？","ENG":"So... which half of what you said was the truth?","TWN":"所以……你所說的那些話中，有一半是真的，那是什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"진실은 내가 네놈 때문에 태어났다는 것.","JPN":"真実は、私があなたのせいで生まれたってこと。","ENG":"The truth is that I was born because of you.","TWN":"事實是，我是因為你而誕生的。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그렇다면 절반의 거짓은?","JPN":"なら、半分の嘘とは？","ENG":"Then the rest was a lie?","TWN":"那假的呢？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"생각해보니 딱히 거짓말은 한 적 없어.","JPN":"考えてみたら、私、別に嘘は言ってないんだよね。","ENG":"Now that I think about it, I didn't really lie.","TWN":"仔細想想，我好像沒有撒過謊。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐야 그게! 제대로 설명해달라고!","JPN":"なんだよそれ！　どういうことかちゃんと説明してってば！","ENG":"What's that supposed to mean?! Explain yourself!","TWN":"那是什麼！給我好好解釋一下！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"서생이 땅내림의 운명을 벗어 던진 날, 내가 태어났다.","JPN":"ショウがチガカリの運命から逃れた日、私が生まれた。","ENG":"The day Seosaeng cast off the fate of the Earthbound, I was born.","TWN":"我誕生於書生擺脫降地命運的那一天。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"여인의 뱃속이 아니라, 녀석이 남긴 운명의 파편에서.","JPN":"女性のお腹からじゃない、やつが残した運命の破片からね。","ENG":"Not from any mother's womb, but from the fragments of fate he left behind.","TWN":"不是在女人的肚子裡，而是在那傢伙留下的命運碎片中。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 추상적인 존재가… 당신을 낳은 거라고요?","JPN":"そんな抽象的な存在が……あなたを生み出したんですか？","ENG":"So an abstract thing... gave birth to you?","TWN":"那種抽象的存在……竟然是你的創造者嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 신화에서 나올 법한 얘기네요.","JPN":"まるで神話のような話ですね。","ENG":"Sounds like something out of a myth.","TWN":"這聽起來像是神話中的故事。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"얜 아까부터 반응이 태평하네.","JPN":"あんた、さっきからよく落ち着いていられるね。","ENG":"Seosaeng's been oddly calm about this.","TWN":"這傢伙從剛才開始反應就很淡定啊。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"서생. 관리자는 네놈을 필요로 해서 불렀다고 했지? 특히 시간을 오가는 그 기술 말이야.","JPN":"ショウ。管理者はあなたが必要だから呼び出した、と言っていたよね？　特に、時間を行き来できるあの技術のために。","ENG":"Seosaeng. The Administrator said he called you because he needed you, right? Especially regarding that technology of traveling through time.","TWN":"書生。管理者說需要你，不是嗎？特別是你那穿越時間的技術。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"분명 그리 말하였네.","JPN":"ああ、そう聞いている。","ENG":"He certainly did.","TWN":"我確實是這麼說的。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"허나 네 힘만으론 그 기술을 재현하지 못한다는 걸 알고 있겠지. 그 기술의 핵심정수가 이 세상엔 존재하지 않으니.","JPN":"でも、知ってるでしょ？　あなたの力だけじゃ、その技術は再現できない。技術の要となる真髄がこの世界には存在しないからね。","ENG":"But you know you can't reproduce it with your power alone. The core essence of that technology doesn't exist in this world.","TWN":"不過你應該知道，光憑你的力量是無法再現那項技術的。因為那項技術的核心精髓在這個世界上並不存在。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내 몸에 흐르는 것이 바로, 그 핵심정수다.","JPN":"そしてこの私の体に流れているものこそが、まさにその真髄ってわけさ。","ENG":"What flows in my body is that very essence.","TWN":"流淌在我體內的，正是那核心精華。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네가 아는 그 범의 피 말이야.","JPN":"あなたの知っている、あの虎の血。","ENG":"The Tiger Blood you know.","TWN":"你所知道的那隻佬虎的血。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"본인이 남긴 운명의 파편이란 것이… 설마 그대인가?","JPN":"某が残した運命の破片とは……まさか、そなたなのか？","ENG":"Those fragments of fate I left... You are one of them?","TWN":"我留下的命運碎片……難道是你嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래. 관리국 기술자로서의 주한과 범의 일부으로서 살아갈 이 몸이니라.","JPN":"そう。管理局の技術者としてのアキヤマ・シスイと、虎の一部として生きてきく、この私だよ。","ENG":"Yes. I will live as Joo Han, a technician of the Administration and as a part of the Tiger.","TWN":"是的。作為管理局的技術人員，我將以老虎的一部分身份生活。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런 게… 가능한 일이었어?","JPN":"そんなこと……ありえるの？","ENG":"That's... even possible?","TWN":"那種事情……是可能的嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"한 사람의 운명으로 두 명 분의 존재가 성립될 수 있다고?","JPN":"1人分の運命で、2人分の存在が成立するなんて？","ENG":"You're saying one person's fate can make two beings' existence valid?","TWN":"一個人的命運可以成就兩個人的存在嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그리 대수로운 일도 아니지.","JPN":"別に大したことじゃないよ。","ENG":"It's not a big deal.","TWN":"這也不是什麼大不了的事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"당장 이쪽 세계에도 한 명 분의 몫의 운명을 열 둘이나 되는 사람이 나눠 갖고 있으니까.","JPN":"こっちの世界にも、1人分の運命を12人もの人が分けて持ってるケースもあるし。","ENG":"In this very world, a dozen people are sharing one person's portion of fate.","TWN":"在這個世界裡，十二個人分擔著一個人的命運。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 말씀대로라면…","JPN":"そのお話の通りだとすると……","ENG":"If that's what you mean...","TWN":"如果按照你所說的……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서생 씨의 땅내림에 얽힐 운명은 완전히 사라진 게 아니었군요.","JPN":"ショウさんのチガカリに関わる運命は、完全に消えたわけではないのですね。","ENG":"Then the fate entangled with Seosaeng's Eathbound wasn't erased completely.","TWN":"書生的命運並沒有完全擺脫地脈之力的束縛。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"세상이 바뀌어도 운명은 운명이지.","JPN":"世の中が変わっても、運命は運命さ。","ENG":"Even if the world changes, fate is still fate.","TWN":"即使世界改變，命運依然存在。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"방향을 바꾸거나 둘로 갈라지게 할 순 있어도 사라지게 하는 건 불가능해.","JPN":"方向を変えたり、2つに分けたりすることはできても、消滅させることはできない。","ENG":"You can change its direction or split it in two, but you can't make it disappear.","TWN":"可以改變方向或分成兩部分，但無法讓它消失。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"제아무리 인과율에 개입하는 힘이라 할지라도 말이야.","JPN":"因果律に介入する力をもってしてもね。","ENG":"Not even a power that interferes with causality can do that.","TWN":"即便是干預因果律的力量，也不過如此。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그렇다면, 그대는 지금껏 어디서 무얼 하고 있었는지 물어봐도 되겠나?","JPN":"ならば、そなたが今までどこで何をしていたか、聞いても良いか？","ENG":"Then, may I ask where you've been and what you've been doing until now?","TWN":"那麼，我可以問問你到現在為止都在做些什麼嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"관리국 지휘부에서 심부름꾼 노릇 좀 하다가, 최근엔 망할 관리국의 우주감옥에 갇혀서 작품 활동을 좀 했지.","JPN":"しばらく管理局の指揮部でお使いをやって、この前はクソ管理局の宇宙刑務所に監禁されて創作活動をちょっとやってたよ。","ENG":"I did some errand-running for the Administration headquarters, then lately I was stuck in their stupid space prison working on my writing.","TWN":"在管理局指揮部跑腿了一陣子，最近被關進了該死的管理局宇宙監獄裡，搞了些創作。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우주감옥이라면… 내가 아는 그 아케론?","JPN":"宇宙刑務所っていうと……あのアケロン？","ENG":"Space prison...? You mean Acheron?","TWN":"宇宙監獄的話…是我知道的那個黃泉嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국이 당신을 감옥에 가둬 놓았다고요?","JPN":"管理局が、あなたを刑務所に監禁したのですか？","ENG":"The Administration locked you in a prison?","TWN":"管理局把你關進監獄了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"관리자 녀석은 내가 너희와 엮이면서 생길 만에 하나라는 변수를 걱정했거든.","JPN":"管理者は私があなたたちと関わることで生じるかもしれない、「万が一」という変数を憂いたの。","ENG":"The Administrator feared even the slightest chance of what might happen if I crossed paths with you.","TWN":"管理者那傢伙擔心我和你們扯上關係後可能會出現變數。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"나도 지금껏 기다려온 게 있으니, 다 된 밥에 재 뿌리고 싶지 않기도 했고.","JPN":"私も今まで散々待たされたのに、その甲斐もなくすべてを水の泡にしたくはなかったし。","ENG":"And I'd been waiting for my own chance, so I wasn't about to spoil things at the finish line.","TWN":"我也一直在等待，不想在最後關頭搞砸。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그렇다는 건…","JPN":"ということは……","ENG":"Which means...","TWN":"也就是說…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 당신도 절반은 사부라는 거지?","JPN":"あんたも、半分は師匠ってことだよね？","ENG":"You're half Master, too?","TWN":"你也算是半個師父了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"운명을 나누었을 뿐이니, 같은 사람이라 볼 순 없다만…","JPN":"運命を分かち合っただけだから、同じ人間とは言えないけど……","ENG":"We only split a fate. Doesn't make us the same person...","TWN":"雖然分擔了命運，但也不能說是同一個人…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 철학적으로 따지면 아주 틀린 얘기도 아니려나?","JPN":"まあ、哲学的に言うなら概ね間違ってないかな？","ENG":"Though philosophically speaking, it isn't entirely wrong.","TWN":"嗯，從哲學上講，這也不算完全錯誤吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"모래고양이 소녀가 된 사부… 좀 귀여울 지도.","JPN":"スナネコの少女になった師匠……ちょっと可愛いかも。","ENG":"Master as a sand cat girl... Might be kind of cute.","TWN":"變成沙漠貓的師父……有點可愛呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭣? 모래고양이?","JPN":"なにっ？　スナネコ？","ENG":"What? Sand cat?","TWN":"什麼？沙貓？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"한 번만 안아봐도 돼?!","JPN":"ちょっとだけ抱きしめてみてもいい！？","ENG":"Can I hug you?!","TWN":"可以讓我抱一下嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"무례하구만. 나이로는 선조 뻘이나 다름없는 이 몸을 감히…","JPN":"失礼だなぁ、私は年齢でいうとあなたの先祖と同じぐらい……","ENG":"Rude. I'm practically your ancestor by age. How dare you–","TWN":"真是無禮。竟敢對我這個年紀上堪比你祖先的人……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"와악!","JPN":"わあっ！","ENG":"WHOA!","TWN":"哇啊！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"여기도 생각보다 부드러운데?","JPN":"ここも意外とモフモフしてる！","ENG":"You're softer here than I expected, too.","TWN":"這裡比想像中還要柔軟呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"잠…! 꼬리는 안돼애!","JPN":"ちょっ……！　尻尾はダメ！","ENG":"Hey...! Not my tail!","TWN":"住手……！不要碰尾巴啊！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…하늘이 맑군요.","JPN":"……空がきれいですね。","ENG":"...The sky's so clear.","TWN":"…天空真晴朗啊。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그래. 어제만 해도 비구름이 가득했는데 말이지.","JPN":"ああ、昨日までは雨雲が広がっていたのにな。","ENG":"It is. Yesterday it was nothing but rain clouds.","TWN":"是啊。昨天還烏雲密佈的。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아시다시피, 마왕 타기리온이 곧 현실로 강림할 겁니다.","JPN":"ご存知だと思いますが、もうじき魔王タギリオンが現実に降臨します。","ENG":"As you know, the Demon Lord Thagirion will soon descend for real.","TWN":"如你所知，魔王塔基里翁即將降臨現實。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무지개가 사라지고 하늘은 붉게 물들겠죠.","JPN":"虹は消え、空は赤く染まるでしょう。","ENG":"Rainbows will vanish, and the sky will burn red.","TWN":"彩虹消失後，天空將被染成紅色。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그 수많은 기적에도 불구하고, 악몽은 어김없이 되풀이되는군.","JPN":"あの無数の奇跡も虚しく、悪夢はまたもや繰り返されるのだな。","ENG":"In spite of all those miracles, the nightmare returns all the same.","TWN":"即便有那麼多的奇蹟，惡夢依然如期重演。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"세상 모든 사람들의 운명의 향방이 이번 결전으로 정해질 거예요.","JPN":"全人類の運命の行く先が、今回の決戦で決まります。","ENG":"This final battle will decide the course of everyone's fate.","TWN":"這次決戰將決定全世界所有人的命運走向。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"흐르고 흐른 끝에 우리의 운명이 한 점에 모였으니.","JPN":"流れ続けた先に我々の運命は一点に集まった。","ENG":"After all that flow, our fates have gathered to a single point.","TWN":"我們的命運川流不息，最終將匯聚於一起。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"세차게 나아간다면 솟아날 구멍이 있지 않겠나?","JPN":"力強く前へ進めば、困難を切り抜ける道は必ずあるだろう。","ENG":"If we push forward with all we have, a way out will surely appear.","TWN":"只要奮力前進，總會有出路的，不是嗎？"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아직도 그 끝이 어디인진 모르겠어요.","JPN":"まだ、終わりは見えません。","ENG":"I still don't know where the end lies.","TWN":"我還是不知道那終點在哪裡。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 제 마음이 허락하는 한, 계속 나아갈 겁니다.","JPN":"ですが、僕の心が許す限り、僕は進み続けるつもりです。","ENG":"But as long as my heart allows it, I'll keep going.","TWN":"心有所指，我會繼續前進。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"...Very well.","TWN":"……嗯。"},"stage":{"bg":"ROOFTOP2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JS_BOTH_NULL_NULL","text":{"KOREA":"마음 향하는 곳에 길이 있는 법이니까.","JPN":"心惹かれる場所に、道はあるものだから。","ENG":"The path lies where the heart points.","TWN":"心之所向，必有路在。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};